async (params, browser) => {
  // Open paper page
  await browser.open(`https://pubmed.ncbi.nlm.nih.gov/${params.pmid}/`)

  // Wait for page
  await browser.waitForSelector('h1.heading-title, .abstract', 15000)

  // Let page render
  await browser.wait(2000)

  // Extract paper info
  const paper_data = await browser.evaluate(`const title = document.querySelector('h1.heading-title')?.textContent?.trim() || ''; const authors = []; document.querySelectorAll('.authors-list a.full-name').forEach(a => authors.push(a.textContent?.trim())); const abstract = document.querySelector('#eng-abstract p, .abstract-content p')?.textContent?.trim() || ''; const doi = document.querySelector('a[data-ga-action="DOI"], .doi a')?.textContent?.trim() || ''; const journal = document.querySelector('.journal-actions button, .cit')?.textContent?.trim() || ''; const keywords = []; document.querySelectorAll('.keywords-list .keyword, .abstract + .keywords a').forEach(k => keywords.push(k.textContent?.trim())); return { pmid: '' + params.pmid + '', title, authors, abstract, doi, journal, keywords, url: window.location.href };`)

  return paper_data
}
